1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const MAIN_ITEM_TYPES = ["sword", "amulet", "staff", "potion"];
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PREMIUM = 60;
15	
16	const isMainItem = (item: any): boolean =>
17	  MAIN_ITEM_TYPES.includes(item.type);
18	
19	const premiumForType = (type: string): number =>
20	  BASE_PREMIUMS[type] ?? 0;
21	
22	const countByType = (items: any[]): Record<string, number> => {
23	  const counts: Record<string, number> = {};
24	  for (const item of items) {
25	    counts[item.type] = (counts[item.type] ?? 0) + 1;
26	  }
27	  return counts;
28	};
29	
30	const calculateComponentPremium = (components: any[]): number => {
31	  const countsByType = countByType(components);
32	  return Object.entries(countsByType).reduce(
33	    (total, [type, count]) =>
34	      total +
35	      (count === COMPONENT_BLOCK_SIZE
36	        ? COMPONENT_BLOCK_PREMIUM
37	        : count * premiumForType(type)),
38	    0,
39	  );
40	};
41	
42	const calculateItemPremium = (item: any): number => {
43	  const base = premiumForType(item.type);
44	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
45	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
46	  return base + cursedSurcharge + enchantmentSurcharge;
47	};
48	
49	export const processScenario = (scenario: any): any => {
50	  let quoteCount = 0;
51	  const results = scenario.steps.map((step: any) => {
52	    quoteCount++;
53	    const mainItems = step.items.filter(isMainItem);
54	    const components = step.items.filter((item: any) => !isMainItem(item));
55	
56	    const mainTotal = mainItems.reduce(
57	      (sum: number, item: any) => sum + calculateItemPremium(item),
58	      0,
59	    );
60	
61	    const componentTotal = calculateComponentPremium(components);
62	
63	    const policyBasePremium = mainItems.reduce(
64	      (sum: number, item: any) => sum + premiumForType(item.type),
65	      0,
66	    ) + componentTotal;
67	
68	    const firstInsurance = policyBasePremium * 0.1;
69	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
70	    const followUpDiscount = quoteCount > 1 ? policyBasePremium * 0.15 : 0;
71	
72	    const premium = mainTotal + componentTotal + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
73	    return { premium };
74	  });
75	  return { results };
76	};
